const fs = require('fs');
const path = require('path');

// Extract form data
const candidateData = {
  fullName: $input.first().json.fullName || '',
  email: $input.first().json.email || '',
  phone: $input.first().json.phone || '',
  collegeName: $input.first().json.collegeName || '',
  skills: $input.first().json.skills || '',
  preferredJobRole: $input.first().json.preferredJobRole || '',
  experienceLevel: $input.first().json.experienceLevel || '',
  resumePDF: $input.first().json.resumePDF || ''
};

// Store resume for processing
return {
  candidateData,
  timestamp: new Date().toISOString(),
  processingId: `placement_${Date.now()}`
};

// Extract text from PDF base64
const pdfBase64 = $input.first().json.candidateData.resumePDF;
const Buffer = require('buffer').Buffer;
const pdfData = Buffer.from(pdfBase64, 'base64');

// Simulate PDF text extraction
// In production, use pdf-parse or similar library
const resumeText = `
[EXTRACTED RESUME TEXT]
Name: ${$input.first().json.candidateData.fullName}
Email: ${$input.first().json.candidateData.email}
Phone: ${$input.first().json.candidateData.phone}
College: ${$input.first().json.candidateData.collegeName}
Skills: ${$input.first().json.candidateData.skills}
Preferred Role: ${$input.first().json.candidateData.preferredJobRole}
Experience: ${$input.first().json.candidateData.experienceLevel}
Resume PDF Size: ${pdfData.length} bytes
`;

return {
  resumeText,
  extractionStatus: 'success',
  processingId: $input.first().json.processingId
};

