// Merge all agent outputs into a comprehensive report
const atsAnalysis = $('ATS Score Analysis Agent').first().json;
const keywordsFetching = $('Keywords Fetching and Suggestion Agent').first().json;
const resumeQuality = $('Overall Resume Analysis Agent').first().json;
const jobMatching = $('Real-Time Job Matching Agent').first().json;
const interviewPrep = $('Interview Preparation Agent').first().json;
const candidateData = $input.first().json.candidateData;

const mergedOutput = {
  candidateSummary: {
    fullName: candidateData.fullName,
    email: candidateData.email,
    phone: candidateData.phone,
    college: candidateData.collegeName,
    targetRole: candidateData.preferredJobRole,
    experienceLevel: candidateData.experienceLevel,
    generatedAt: new Date().toISOString()
  },
  atsAnalysis: atsAnalysis,
  keywordAnalysis: keywordsFetching,
  resumeAnalysis: resumeQuality,
  jobRecommendations: jobMatching,
  interviewPreparation: interviewPrep,
  dataIntegrity: {
    allAgentsExecuted: true,
    timestamp: new Date().toISOString()
  }
};

return mergedOutput;

